 */
function scoreSubtype(
  email: EmailMessage,
  subtypeData: SubtypeDefinition,
  subtypeCode: string,
  tuningParams: RuleScoringStageConfig['tuningParameters']
): SubtypeScore {
  const ruleClassification = subtypeData.ruleBasedClassification || {};
  const matches: RuleScoringMatch[] = [];

  // Process each confidence tier with bounded aggregation
  const confidenceTiers: Array<{
    tier: keyof SubtypeRuleClassification;
    multiplier: number;
    maxMatches: number;
  }> = [
    { tier: 'highConfidence', multiplier: 1.0, maxMatches: tuningParams.KHigh },
    { tier: 'mediumConfidence', multiplier: tuningParams.M_medium, maxMatches: tuningParams.KMedium },
    { tier: 'lowConfidence', multiplier: tuningParams.M_low, maxMatches: tuningParams.KLow },
  ];

  let totalScore = 0;

  for (const { tier, multiplier, maxMatches } of confidenceTiers) {
    const tierRules = ruleClassification[tier] || [];
    const tierMatches: RuleScoringMatch[] = [];

    for (const rule of tierRules) {
      const match = matchRulePattern(email, rule);

      if (match.matched) {
        tierMatches.push({
          tier,
          field: rule.field,
          operation: rule.operation,
          values: rule.values || [],
          weight: rule.weight,
          matchedValue: match.matchedValue,
          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
          partialMatch: false, // For compatibility with RuleMatch base interface
        });

        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
      }
    }

    // Apply bounded aggregation - take top K matches for this tier
    const topMatches = tierMatches.sort((a, b) => b.weight - a.weight).slice(0, maxMatches);

    // Add to total score and matches
    for (const match of topMatches) {
      totalScore += match.weight * multiplier;
      matches.push(match);
    }
  }

  return {
    totalScore,
    ruleMatches: matches,
    aggregationBreakdown: matches.length > 0 ? matches.map((m) => `${m.tier}:${m.weight}`).join(',') : 'noMatches',
  };
}

