   235→ *                + sum(medium_match_weights) * KMedium
   236→ *                + sum(low_match_weights) * KLow
   237→ */
   238→function scoreSubtype(
   239→  email: EmailMessage,
   240→  subtypeData: SubtypeDefinition,
   241→  subtypeCode: string,
   242→  tuningParams: RuleScoringStageConfig['tuningParameters']
   243→): SubtypeScore {
   244→  const ruleClassification = subtypeData.ruleBasedClassification || {};
   245→  const matches: RuleScoringMatch[] = [];
   246→
   247→  // Process each confidence tier: sum ALL matches, then multiply by K
   248→  const confidenceTiers: Array<{
   249→    tier: keyof SubtypeRuleClassification;
   250→    multiplier: number; // K parameter (multiplier applied to sum of weights)
   251→  }> = [
   252→    { tier: 'highConfidence', multiplier: tuningParams.KHigh },
   253→    { tier: 'mediumConfidence', multiplier: tuningParams.KMedium },
   254→    { tier: 'lowConfidence', multiplier: tuningParams.KLow },
   255→  ];
   256→
   257→  let totalScore = 0;
   258→  const tierBreakdowns: string[] = [];
   259→
   260→  for (const { tier, multiplier } of confidenceTiers) {
   261→    const tierRules = ruleClassification[tier] || [];
   262→    const tierMatches: RuleScoringMatch[] = [];
   263→    let tierWeightSum = 0;
   264→
   265→    for (const rule of tierRules) {
   266→      const match = matchRulePattern(email, rule);
   267→
   268→      if (match.matched) {
   269→        tierMatches.push({
   270→          tier,
   271→          field: rule.field,
   272→          operation: rule.operation,
   273→          values: rule.values || [],
   274→          weight: rule.weight,
   275→          matchedValue: match.matchedValue,
   276→          ruleId: `${subtypeCode}_${tier}_${tierMatches.length}`,
   277→          ruleWeight: rule.weight, // For compatibility with RuleMatch base interface
   278→          partialMatch: false, // For compatibility with RuleMatch base interface
   279→        });
   280→
   281→        tierWeightSum += rule.weight;
   282→        console.log(`Rule match - ${tier} in ${rule.field}: "${match.matchedValue}" (weight: ${rule.weight})`);
   283→      }
   284→    }
   285→
   286→    // Apply K multiplier to sum of ALL tier weights (not topK limit)
   287→    if (tierWeightSum > 0) {
   288→      const tierScore = tierWeightSum * multiplier;
   289→      totalScore += tierScore;
   290→      tierBreakdowns.push(`${tier}:sum(${tierWeightSum})*${multiplier}=${tierScore.toFixed(2)}`);
   291→
   292→      // Add all matches to the result (not just topK)
   293→      matches.push(...tierMatches);
   294→    }
   295→  }
   296→
   297→  return {
   298→    totalScore,
   299→    ruleMatches: matches,
   300→    aggregationBreakdown: tierBreakdowns.length > 0 ? tierBreakdowns.join(' + ') : 'noMatches',
   301→  };
   302→}
   303→
   304→/**
   305→ * Calculate bounded aggregation score to prevent inflation
   306→ * Uses diminishing returns: primary subtype + dampened tail support
   307→ */
   308→function calculateBoundedAggregation(
   309→  subtypeScores: Record<string, SubtypeScore>,
   310→  tuningParams: RuleScoringStageConfig['tuningParameters']
   311→): { totalScore: number; breakdown: string } {
   312→  const scores = Object.entries(subtypeScores)
   313→    .map(([subtype, data]) => ({ subtype, score: data.totalScore }))
   314→    .sort((a, b) => b.score - a.score); // Sort by score descending
   315→
   316→  if (scores.length === 0) {
   317→    return { totalScore: 0, breakdown: 'noSubtypes' };
   318→  }
   319→
   320→  // Primary subtype (highest score) contributes fully
   321→  const primaryScore = scores[0].score;
   322→  const primarySubtype = scores[0].subtype;
   323→
   324→  // Tail support: additional subtypes contribute with diminishing returns
   325→  let tailSupport = 0;
   326→  const tailContributions: string[] = [];
   327→
   328→  if (scores.length > 1) {
   329→    const tailScores = scores.slice(1);
   330→
   331→    for (const tail of tailScores) {
   332→      const contribution = tail.score * tuningParams.TAIL_DAMPEN;
   333→      tailSupport += contribution;
   334→      tailContributions.push(`${tail.subtype}:${contribution.toFixed(1)}`);
   335→    }
   336→
   337→    // Apply tail ratio cap
   338→    const maxTailSupport = primaryScore * tuningParams.TAIL_RATIO_CAP;
   339→    tailSupport = Math.min(tailSupport, maxTailSupport);
   340→  }
   341→
   342→  const totalScore = primaryScore + tailSupport;
   343→  const breakdown =
   344→    `primary:${primarySubtype}:${primaryScore}` +
   345→    (tailSupport > 0 ? ` + tail:${tailSupport.toFixed(1)}(${tailContributions.join(',')})` : '');
   346→
   347→  return { totalScore, breakdown };
   348→}
   349→
   350→/**
   351→ * Calculate confidence percentage based on score and number of matches
   352→ */
   353→function calculateConfidence(score: number, numMatches: number): number {
   354→  if (score === 0) return 0;
   355→
   356→  // Basic confidence calculation: higher scores and more matches = higher confidence
   357→  // Cap at 95% to leave room for AI enhancement
   358→  const baseConfidence = Math.min(score * 5, 80); // 5% per point, max 80%
   359→  const matchBonus = Math.min(numMatches * 3, 15); // 3% per match, max 15%
   360→
   361→  return Math.min(baseConfidence + matchBonus, 95);
   362→}
   363→
   364→/**
   365→ * Select the best subtype based on scores
   366→ */
   367→function selectBestSubtype(subtypeScores: Record<string, SubtypeScore>): string | null {
   368→  if (!subtypeScores || Object.keys(subtypeScores).length === 0) {
   369→    return null;
   370→  }
