/**
 * Unit Tests for Rule-Based Scoring Stage
 *
 * Tests the sophisticated lexical pattern matching, bounded aggregation, and scoring logic
 * per SCORING_LOGIC.md "Subtype Scoring Formula" section.
 *
 * Constitutional Compliance:
 * - Law 0: Preserves sophisticated classification engine architecture
 * - Law 1: Comprehensive edge case testing prevents functional harm
 * - Law 2: Tests match implementation requirements exactly
 * - Law 3: Clear, maintainable test structure with explainability validation
 */

import {
  executeRuleScoring,
  RuleScoringStageConfig,
  RuleScoringStageConfigSchema,
} from '../../src/stages/rule-scoring';
import {
  AIPromptSystem,
  AttributeRelevanceMatrix,
  AttributeSystem,
  DomainOverrides,
  DomainResolution,
  EmailMessage,
  JSONSchema,
  MultiLabelPolicy,
  ProcessingConfig,
  ProcessingSettings,
  TopLevelCategory,
} from '../../src/types';
import { createClassificationResult, createClassificationSession } from '../../src/utils/initialization';

// Helper function to set up test session and result
function setupTest() {
  const settings: ProcessingSettings = {
    initialization: {
      applyHardAssertions: true,
      seedCategoryScores: true,
    },
    ruleScoring: {
      useLexicalPatterns: true,
      applySubtypeRules: true,
      boundedAggregation: true,
    },
    attributeProcessing: {
      detectSelfSent: true,
      resolveDomains: true,
      deriveContextFlags: true,
    },
    attributeInfluence: {
      applyBonuses: true,
      applyPenalties: true,
      enforceCaps: true,
    },
    multiLabelSelection: {
      maxLabels: 3,
      minSecondaryConfidence: 0.5,
      allowedCombinations: [],
    },
    aiRouting: {
      highConfidenceThreshold: 0.8,
      aiRequiredThreshold: 0.3,
      skipAiConditions: [],
    },
  };

  const multiLabelPolicy: MultiLabelPolicy = {
    maxTopLevelLabels: 3,
    minConfidenceForAdditional: 0.5,
    allowFinancialActionableCopresence: true,
  };

  const domainOverrides: DomainOverrides = {};

  const domainResolution: DomainResolution = {
    mode: 'runtimeResolved',
    source: 'config/domain-sources.json',
    notes: 'Test config',
  };

  const attributes: AttributeSystem = {
    schema: {},
    detectors: [],
    derived: {},
    attributeBonusMap: {},
  };

  const attributeRelevance: AttributeRelevanceMatrix = {
    RolesLegend: {
      CORE: 'Core attribute',
      PRIMARY_BOOST: 'Primary boost',
      SECONDARY_BOOST: 'Secondary boost',
      DISAMBIGUATOR: 'Disambiguator',
      FILTER: 'Filter',
      STRUCTURAL: 'Structural',
      DERIVED_LINK: 'Derived link',
      NEUTRAL: 'Neutral',
    },
  };

  const aiPrompts: AIPromptSystem = {
    featureExtraction: {
      systemPrompt: ['Extract features'],
      userPrompt: ['Analyze email'],
    },
    finalClassification: {
      systemPrompt: ['Classify email'],
      userPrompt: ['Determine category'],
    },
  };

  const featureExtractionSchema: JSONSchema = {
    type: 'object',
    properties: {},
    required: [],
    additionalProperties: false,
  };

  const processingConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: '',
    settings,
    categorySignals: {},
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.2,
      aiClassificationRequired: 0.3,
      manualReviewRequired: 0.1,
      secondaryLabelMinGap: 0.15,
    },
    multiLabelPolicy: multiLabelPolicy,
    domainSignalOverrides: domainOverrides,
    domainSignalResolution: domainResolution,
    topLevelCategories: {},
    attributes,
    attributeRelevance: attributeRelevance,
    aiPrompts: aiPrompts,
    featureExtractionSchema: featureExtractionSchema,
  };

  const session = createClassificationSession(processingConfig, 'sequential', 1);
  const result = createClassificationResult('test-email-id', session.id, 0);

  // Initialize score breakdown with empty structure
  result.scoreBreakdown.categoryScores = {};

  return { session, result };
}

describe('Rule-Based Scoring Stage', () => {
  let mockEmail: EmailMessage;
  let mockConfig: RuleScoringStageConfig;

  beforeEach(() => {
    // Mock email with rich content for testing various rules
    mockEmail = {
      id: 'test-email-001',
      threadId: 'thread-001',
      gmailLabels: [],
      subject: 'Receipt for your purchase - Order #INV-2024-001',
      from: {
        email: 'receipts@store.com',
        name: 'Store Receipts',
        raw: 'Store Receipts <receipts@store.com>',
      },
      to: [
        {
          email: 'customer@example.com',
          name: 'Customer',
          raw: 'Customer <customer@example.com>',
        },
      ],
      date: new Date('2025-09-28T14:30:00Z'),
      bodyPlain: `Thank you for your purchase!

Order Details:
- Order #: INV-2024-001
- Total: $129.99
- Payment Method: Credit Card ending in 4567
- Date: September 28, 2025

Items:
1. Wireless Headphones - $99.99
2. Shipping - $9.99
3. Tax - $20.01

Your order will be shipped within 2 business days.`,
      bodyHtml: '<h1>Thank you for your purchase!</h1><p>Total: $129.99</p>',
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'Message-ID', value: '<receipt-001@store.com>' },
          { name: 'From', value: 'Store Receipts <receipts@store.com>' },
          { name: 'Subject', value: 'Receipt for your purchase - Order #INV-2024-001' },
        ],
      },
      isProcessed: false,
      processingPriority: 1,
    };

    // Mock configuration with realistic rule patterns
    mockConfig = {
      settings: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Purchase receipts and confirmations',
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['receipt', 'payment confirmation', 'order confirmation'],
                    weight: 12,
                  },
                ],
                mediumConfidence: [
                  {
                    field: 'body',
                    operation: 'containsAny',
                    values: ['total', 'amount', 'charged', 'purchase'],
                    weight: 6,
                  },
                  {
                    field: 'body',
                    operation: 'regexAny',
                    values: ['\\$\\d+\\.\\d{2}', 'USD \\d+'],
                    weight: 8,
                  },
                ],
                lowConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['order', 'item'],
                    weight: 3,
                  },
                ],
              },
            },
            invoice: {
              description: 'Invoices and billing statements',
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['invoice', 'bill', 'statement'],
                    weight: 12,
                  },
                ],
              },
            },
          },
        },
        actionable: {
          description: 'Action-required emails',
          subtypes: {
            explicitAction: {
              description: 'Emails with explicit action requests',
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'startsWith',
                    values: ['TODO:', 'ACTION:', 'TASK:', 'URGENT:'],
                    weight: 15,
                  },
                ],
                mediumConfidence: [
                  {
                    field: 'body',
                    operation: 'containsAny',
                    values: ['please review', 'action required', 'respond by'],
                    weight: 7,
                  },
                ],
              },
            },
          },
        },
      },
      tuningParameters: {
        KHigh: 2,
        KMedium: 2,
        KLow: 2,
        TAIL_DAMPEN: 0.5,
        TAIL_RATIO_CAP: 0.3,
      },
    };
  });

  describe('Configuration Validation', () => {
    it('should validate valid configuration successfully', () => {
      const result = RuleScoringStageConfigSchema.safeParse(mockConfig);
      expect(result.success).toBe(true);
    });

    it('should reject invalid tuning parameters', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {}, // Empty categories
        tuningParameters: {
          ...mockConfig.tuningParameters,
          KHigh: -1, // Invalid - must be >= 0
          KMedium: -0.5, // Invalid - must be >= 0
          M_medium: 1.5, // Invalid - must be <= 1
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
      expect(result.error?.issues.length).toBeGreaterThanOrEqual(3); // At least 3 errors (KHigh, KMedium, M_medium)
    });

    it('should reject unknown rule operations', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Test',
            subtypes: {
              test: {
                description: 'Test',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'invalidOperation' as string,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
    });
  });

  describe('executeRuleScoring()', () => {
    it('should process emails with rule matches successfully', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring.length).toBeGreaterThan(0);
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBeGreaterThan(0);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
    });

    it('should calculate sophisticated bounded aggregation correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult).toBeDefined();
      expect(financialResult!.subtypeScores.receipt).toBeDefined();

      // Should have multiple rule matches with different weights
      const receiptScore = financialResult!.subtypeScores.receipt;
      expect(receiptScore.ruleMatches.length).toBeGreaterThan(1);
      expect(receiptScore.totalScore).toBeGreaterThan(12); // High confidence + medium matches

      // Verify bounded aggregation breakdown
      expect(receiptScore.aggregationBreakdown).toContain(':');
      expect(financialResult!.scoringRationale[0]).toContain('Rule aggregation:');
    });

    it('should handle emails with no rule matches', () => {
      const emptyEmail: EmailMessage = {
        ...mockEmail,
        subject: 'Random subject with no patterns',
        bodyPlain: 'This is just random content with no matching patterns',
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(0);
    });

    it("should preserve existing scores when rules don't improve them", () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      // Set high existing score
      result.scoreBreakdown.categoryScores.financial = {
        baseScore: 25.0,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: 25.0,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should use max of existing vs rule score
      expect(result.scoreBreakdown.categoryScores.financial.finalScore).toBeGreaterThanOrEqual(25.0);
    });

    it('should handle disabled rule scoring settings', () => {
      const disabledConfig = {
        ...mockConfig,
        settings: {
          useLexicalPatterns: false,
          applySubtypeRules: false,
          boundedAggregation: true,
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, disabledConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      // Disabled config should not produce rule scoring results
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(0);
    });

    it('should update context tracking properly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.configurationRefs.ruleScoring).toBe(
        'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification'
      );
    });

    it('should handle multiple categories with matches', () => {
      const multiCategoryEmail: EmailMessage = {
        ...mockEmail,
        subject: 'TODO: Review receipt for meeting expenses',
        bodyPlain: 'Please review the total amount charged: $50.00',
      };

      const { session, result } = setupTest();
      result.emailId = multiCategoryEmail.id;
      executeRuleScoring(multiCategoryEmail, session, result, mockConfig);

      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(2);
      expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBeGreaterThan(0);
      expect(result.scoreBreakdown.categoryScores.actionable?.finalScore).toBeGreaterThan(0);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const actionableResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'actionable');

      expect(financialResult?.selectedSubtypeId).toBe('receipt');
      expect(actionableResult?.selectedSubtypeId).toBe('explicitAction');
    });
  });

  describe('Rule Evaluation Functions', () => {
    describe('containsAny operation', () => {
      it('should match any value in the list', () => {
        // Test subject content directly via stage execution
        const testEmail = { ...mockEmail, subject: 'Your receipt is ready' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        expect(financialResult?.ruleMatches.some((match) => match.matchedValue === 'receipt')).toBe(true);
      });

      it('should be case insensitive', () => {
        const testEmail = { ...mockEmail, subject: 'RECEIPT for your order' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        expect(financialResult?.ruleMatches.some((match) => match.operation === 'containsAny')).toBe(true);
      });

      it('should not match when no values are found', () => {
        const testEmail = { ...mockEmail, subject: 'Random subject' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        const subjectMatches =
          financialResult?.ruleMatches.filter(
            (match) => match.field === 'subject' && match.operation === 'containsAny'
          ) || [];
        expect(subjectMatches.length).toBe(0);
      });
    });

    describe('startsWith operation', () => {
      it('should match prefixes correctly', () => {
        const testEmail = { ...mockEmail, subject: 'TODO: Review this document' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const actionableResult = result.explainabilityTrace.ruleScoring.find(
          (cat) => cat.categoryCode === 'actionable'
        );
        expect(
          actionableResult?.ruleMatches.some(
            (match) => match.operation === 'startsWith' && match.matchedValue === 'TODO:'
          )
        ).toBe(true);
      });

      it('should be case insensitive for startsWith', () => {
        const testEmail = { ...mockEmail, subject: 'todo: check this' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const actionableResult = result.explainabilityTrace.ruleScoring.find(
          (cat) => cat.categoryCode === 'actionable'
        );
        expect(actionableResult?.ruleMatches.length).toBeGreaterThan(0);
      });
    });

    describe('regexAny operation', () => {
      it('should match regex patterns correctly', () => {
        const testEmail = { ...mockEmail, bodyPlain: 'The total cost is $129.99' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        const regexMatches = financialResult?.ruleMatches.filter((match) => match.operation === 'regexAny') || [];
        expect(regexMatches.length).toBeGreaterThan(0);
        expect(regexMatches[0].matchedValue).toMatch(/\$\d+\.\d{2}/);
      });

      it('should handle invalid regex gracefully', () => {
        const invalidRegexConfig = {
          ...mockConfig,
          topLevelCategories: {
            testCategory: {
              description: 'Test',
              subtypes: {
                testSubtype: {
                  description: 'Test',
                  ruleBasedClassification: {
                    mediumConfidence: [
                      {
                        field: 'body',
                        operation: 'regexAny' as const,
                        values: ['[invalid regex pattern'],
                        weight: 5,
                      },
                    ],
                  },
                },
              },
            },
          },
        };

        // Spy on console.log to check error handling
        const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

        const { session, result } = setupTest();
        result.emailId = mockEmail.id;
        executeRuleScoring(mockEmail, session, result, invalidRegexConfig);

        expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Invalid regex pattern'));
        consoleSpy.mockRestore();
      });
    });

    describe('exists operation', () => {
      it('should match when field has content', () => {
        const existsConfig = {
          ...mockConfig,
          topLevelCategories: {
            testCategory: {
              description: 'Test',
              subtypes: {
                hasSubject: {
                  description: 'Test',
                  ruleBasedClassification: {
                    lowConfidence: [
                      {
                        field: 'subject',
                        operation: 'exists' as const,
                        values: [],
                        weight: 2,
                      },
                    ],
                  },
                },
              },
            },
          },
        };

        const { session, result } = setupTest();
        result.emailId = mockEmail.id;
        executeRuleScoring(mockEmail, session, result, existsConfig);

        const testResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'testCategory');
        expect(testResult?.ruleMatches.some((match) => match.operation === 'exists')).toBe(true);
      });
    });
  });

  describe('Bounded Aggregation Logic', () => {
    it('should apply KHigh multiplier to sum of ALL high confidence match weights', () => {
      const multiHighConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Test with many high confidence rules',
                ruleBasedClassification: {
                  highConfidence: [
                    { field: 'subject', operation: 'containsAny', values: ['receipt'], weight: 12 },
                    { field: 'subject', operation: 'containsAny', values: ['purchase'], weight: 11 },
                    { field: 'subject', operation: 'containsAny', values: ['order'], weight: 10 },
                    { field: 'body', operation: 'containsAny', values: ['total'], weight: 9 },
                  ],
                },
              },
            },
          },
        },
        tuningParameters: {
          ...mockConfig.tuningParameters,
          KHigh: 1.5, // Multiplier for high confidence tier
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for your purchase order',
        bodyPlain: 'Total amount: $50',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiHighConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      // Per SCORING_LOGIC.md: sum(high_match_weights) * KHigh
      // All 4 rules match: 12 + 11 + 10 + 9 = 42
      // 42 * 1.5 = 63
      const highMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'highConfidence') || [];
      expect(highMatches.length).toBe(4); // All matches included (not topK)

      // Verify score calculation: sum of weights * multiplier
      const highWeightSum = highMatches.reduce((sum, m) => sum + m.weight, 0);
      expect(highWeightSum).toBe(42); // 12 + 11 + 10 + 9
      expect(receiptScore?.totalScore).toBe(63); // 42 * 1.5
    });

    it('should apply multipliers to medium and low confidence tiers', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      const mediumMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'mediumConfidence') || [];
      const lowMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'lowConfidence') || [];

      // Verify tiers are properly categorized
      if (mediumMatches.length > 0) {
        expect(mediumMatches[0].tier).toBe('mediumConfidence');
      }
      if (lowMatches.length > 0) {
        expect(lowMatches[0].tier).toBe('lowConfidence');
      }
    });

    it('should calculate tail support with dampening', () => {
      const multiSubtypeConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Receipt',
                ruleBasedClassification: {
                  highConfidence: [{ field: 'subject', operation: 'containsAny', values: ['receipt'], weight: 15 }],
                },
              },
              invoice: {
                description: 'Invoice',
                ruleBasedClassification: {
                  highConfidence: [{ field: 'subject', operation: 'containsAny', values: ['order'], weight: 12 }],
                },
              },
            },
          },
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for order confirmation',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiSubtypeConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.scoringRationale[0]).toContain('primary:');

      // Should have both receipt and invoice subtypes with scores
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('receipt');
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('invoice');
    });
  });

  describe('Confidence Calculation', () => {
    it('should calculate confidence based on score and match count', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBeGreaterThan(0);
      expect(financialResult?.confidence).toBeLessThanOrEqual(95); // Capped at 95%
    });

    it('should return 0 confidence for zero scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No matching patterns',
        bodyPlain: 'No matching content',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBe(0);
    });
  });

  describe('Subtype Selection', () => {
    it('should select highest scoring subtype', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBe('receipt');
    });

    it('should return null when no subtypes have scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No patterns',
        bodyPlain: 'No patterns',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBeNull();
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing subject and body fields', () => {
      const incompleteEmail: EmailMessage = {
        ...mockEmail,
        subject: '', // Empty subject instead of undefined
        bodyPlain: undefined,
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = incompleteEmail.id;
      executeRuleScoring(incompleteEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
    });

    it('should handle empty values arrays in rules', () => {
      const emptyValuesConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              emptyValues: {
                description: 'Test empty values',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'containsAny' as const,
                      values: [],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, emptyValuesConfig);

      // Should handle gracefully without errors
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle subtypes without ruleBasedClassification', () => {
      const noRulesConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              noRules: {
                description: 'Subtype without rules',
                // No ruleBasedClassification
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, noRulesConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle unknown rule fields gracefully', () => {
      const unknownFieldConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              unknownField: {
                description: 'Test unknown field',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'unknownField',
                      operation: 'containsAny' as const,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, unknownFieldConfig);

      // Should not crash, should handle gracefully
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });

  describe('Performance and Explainability', () => {
    it('should complete processing within reasonable time limits', () => {
      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(1000); // Should complete in under 1 second
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeLessThan(1000);
    });

    it('should provide complete explainability information', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      for (const categoryResult of result.explainabilityTrace.ruleScoring) {
        if (Object.keys(categoryResult.subtypeScores).length > 0) {
          expect(categoryResult.scoringRationale.length).toBeGreaterThan(0);
          expect(categoryResult.ruleMatches).toBeDefined();

          for (const match of categoryResult.ruleMatches) {
            expect(match.field).toBeDefined();
            expect(match.operation).toBeDefined();
            expect(match.tier).toBeDefined();
            expect(match.matchedValue).toBeDefined();
            expect(match.ruleId).toBeDefined();
            expect(match.weight).toBeGreaterThan(0);
          }
        }
      }
    });

    it('should generate consistent results across multiple runs', () => {
      const { session: session1, result: result1 } = setupTest();
      result1.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session1, result1, mockConfig);

      const { session: session2, result: result2 } = setupTest();
      result2.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session2, result2, mockConfig);

      // Compare score breakdowns
      expect(result1.scoreBreakdown.categoryScores).toEqual(result2.scoreBreakdown.categoryScores);
      // Compare explainability traces
      expect(result1.explainabilityTrace.ruleScoring).toEqual(result2.explainabilityTrace.ruleScoring);
    });
  });

  describe('Integration with Classification Pipeline', () => {
    it('should preserve result structure correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should populate result with proper structure
      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should work with empty initial category scores', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(Object.keys(result.scoreBreakdown.categoryScores).length).toBeGreaterThan(0);
    });

    it('should handle large configuration files efficiently', () => {
      // Create a config with many categories and rules
      const largeConfig = {
        ...mockConfig,
        topLevelCategories: {},
      };

      // Generate 10 categories with 5 subtypes each
      for (let i = 0; i < 10; i++) {
        const categoryName = `category_${i}`;
        (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName] = {
          description: `Category ${i}`,
          subtypes: {},
          aiFinalClassification: {
            categoryDescription: `AI classification for category ${i}`,
            decisionCriteria: [`Criteria for category ${i}`],
          },
        };

        for (let j = 0; j < 5; j++) {
          const subtypeName = `subtype_${i}_${j}`;
          (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName].subtypes[subtypeName] = {
            description: `Subtype ${i} ${j}`,
            ruleBasedClassification: {
              highConfidence: [
                {
                  field: 'subject',
                  operation: 'containsAny',
                  values: [`pattern_${i}_${j}`],
                  weight: 10,
                },
              ],
            },
          };
        }
      }

      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, largeConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(2000); // Should handle large configs efficiently
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });
});

import { z } from 'zod';

/**
 * Zod schema for CategoryConfiguration validation
 * Validates structure per ${repoRoot}/docs/SCORING_LOGIC.md "Tuning Parameters Summary" section
 */

// Base validation schemas for reusability
const EmailAddressSchema = z.string().email();
const DomainSchema = z.string().regex(/^[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}$/, 'Invalid domain format');
const ConfidenceSchema = z.string().regex(/^(high|medium|low)$/, 'Must be high, medium, or low');
const WeightSchema = z.number().min(0).max(1);
const ThresholdSchema = z.number().min(0).max(1);

// Rule pattern validation
export const RulePatternSchema = z.object({
  field: z.enum(['subject', 'body', 'from.address', 'from.name', 'to', 'headers']),
  operation: z.enum(['containsAny', 'startsWith', 'endsWith', 'regexAny', 'exists', 'notContains']),
  values: z.array(z.string()).optional(),
  weight: WeightSchema,
});

// Attribute schemas
const AttributeRoleSchema = z.enum([
  'CORE',
  'PRIMARY_BOOST',
  'SECONDARY_BOOST',
  'DISAMBIGUATOR',
  'FILTER',
  'STRUCTURAL',
  'DERIVED_LINK',
  'NEUTRAL',
]);

const AttributeSchemaDefinition = z.object({
  type: z.enum(['enum', 'boolean', 'string', 'number']),
  values: z.array(z.string()).optional(),
  description: z.string(),
  validation: z
    .object({
      required: z.boolean().default(false),
      min: z.number().optional(),
      max: z.number().optional(),
      pattern: z.string().optional(),
    })
    .optional(),
});

const AttributeDetectorSchema = z.object({
  attribute: z.string(),
  field: z.string(),
  operation: z.string(),
  values: z.array(z.string()),
  confidence: z.number().min(0).max(1).default(1.0),
  parallelSafe: z.boolean().default(true),
});

const DerivedAttributeSchema = z.object({
  logic: z.string(),
  notes: z.string(),
  dependencies: z.array(z.string()).default([]),
  parallelSafe: z.boolean().default(false),
});

// Domain reference schemas
const DomainReferenceSchema = z.object({
  sourceGroup: z.string(),
  confidence: ConfidenceSchema,
});

// Category signal schemas
const HardAssertionsSchema = z.object({
  fromDomainsRef: DomainReferenceSchema.optional(),
  subjectPrefixes: z.array(z.string()).optional(),
  fromAddresses: z.array(EmailAddressSchema).optional(),
  customRules: z.array(RulePatternSchema).optional(),
});

const StrongIndicatorsSchema = z.object({
  fromDomainsRef: DomainReferenceSchema.optional(),
  subjectContains: z.array(z.string()).optional(),
  bodyContains: z.array(z.string()).optional(),
  customRules: z.array(RulePatternSchema).optional(),
  diminishingReturns: z
    .object({
      enabled: z.boolean().default(true),
      decayFactor: z.number().min(0).max(1).default(0.8),
      maxIndicators: z.number().int().min(1).default(5),
    })
    .optional(),
});

const DisambiguatorsSchema = z.object({
  boostIfPresentAttributes: z.array(z.string()).optional(),
  suppressIfBodyContains: z.array(z.string()).optional(),
  boostIfAbsentCategories: z.array(z.string()).optional(),
  pairwiseAdjustments: z
    .array(
      z.object({
        targetCategory: z.string(),
        condition: z.string(),
        adjustment: z.number().min(-1).max(1),
        reason: z.string(),
      })
    )
    .optional(),
});

const CategorySignalsSchema = z.object({
  hardAssertions: HardAssertionsSchema.optional(),
  strongIndicators: StrongIndicatorsSchema.optional(),
  disambiguators: DisambiguatorsSchema.optional(),
  validation: z
    .object({
      requiredFields: z.array(z.string()).default([]),
      mutuallyExclusive: z.array(z.array(z.string())).default([]),
    })
    .optional(),
});

const ActionSchema = z.object({
  gmailLabel: z.string().nullable(),
  archive: z.boolean(),
  markAsRead: z.boolean(),
  autoDelete: z.boolean(),
  customActions: z.array(z.string()).optional(),
});

// Subtype definition schema
const SubtypeDefinitionSchema = z.object({
  description: z.string(),
  actions: ActionSchema.optional(),
  ruleBasedClassification: z
    .object({
      highConfidence: z.array(RulePatternSchema).optional(),
      mediumConfidence: z.array(RulePatternSchema).optional(),
      lowConfidence: z.array(RulePatternSchema).optional(),
    })
    .optional(),
  derived: z.boolean().default(false),
  derivationLogic: z.string().optional(),
  parallelSafe: z.boolean().default(true),
  tuningParameters: z
    .object({
      KHigh: z.number().min(0).default(1.0),
      KMedium: z.number().min(0).default(0.7),
      KLow: z.number().min(0).default(0.3),
      maxRuleScore: z.number().min(0).default(1.0),
    })
    .optional(),
});

// Top level category schema
const TopLevelCategorySchema = z.object({
  description: z.string(),
  actions: ActionSchema.optional(),
  subtypes: z.record(z.string(), SubtypeDefinitionSchema),
  aiFinalClassification: z.object({
    categoryDescription: z.string(),
    decisionCriteria: z.array(z.string()),
    exclusionCriteria: z.array(z.string()).optional(),
    promptTemplate: z.string().optional(),
  }),
  tuningParameters: z
    .object({
      confidenceBoost: z.number().min(0).max(1).default(0),
      priorityWeight: z.number().min(0).max(2).default(1.0),
      maxScoreCap: z.number().min(0).default(1.0),
    })
    .optional(),
});

// Processing settings schema
const ProcessingSettingsSchema = z.object({
  initialization: z.object({
    applyHardAssertions: z.boolean().default(true),
    seedCategoryScores: z.boolean().default(true),
    parallelInitialization: z.boolean().default(true).optional(),
  }),
  ruleScoring: z.object({
    useLexicalPatterns: z.boolean().default(true),
    applySubtypeRules: z.boolean().default(true),
    boundedAggregation: z.boolean().default(true),
    parallelRuleEvaluation: z.boolean().default(true).optional(),
    tuningParameters: z
      .object({
        KHigh: z.number().min(0).default(1.0),
        KMedium: z.number().min(0).default(0.7),
        KLow: z.number().min(0).default(0.3),
        M_medium: z.number().min(0).max(1).default(0.7),
        M_low: z.number().min(0).max(1).default(0.3),
        TAIL_DAMPEN: z.number().min(0).max(1).default(0.5),
        TAIL_RATIO_CAP: z.number().min(0).max(1).default(0.3),
        aggregationCap: z.number().min(0).default(1.0),
      })
      .optional(),
  }),
  attributeProcessing: z.object({
    detectSelfSent: z.boolean().default(true),
    resolveDomains: z.boolean().default(true),
    deriveContextFlags: z.boolean().default(true),
    parallelDetection: z.boolean().default(true).optional(),
    cacheAttributeResults: z.boolean().default(true).optional(),
  }),
  attributeInfluence: z.object({
    applyBonuses: z.boolean().default(true),
    applyPenalties: z.boolean().default(true),
    enforceCaps: z.boolean().default(true),
    parallelInfluenceCalculation: z.boolean().default(true).optional(),
    tuningParameters: z
      .object({
        bonusMultiplier: z.number().min(0).default(1.0),
        penaltyMultiplier: z.number().min(0).default(1.0),
        maxTotalBonus: z.number().min(0).default(0.5),
        maxTotalPenalty: z.number().min(0).default(0.3),
      })
      .optional(),
  }),
  strongIndicators: z
    .object({
      baseWeight: z.number().min(0).default(10).optional(),
      diminishingReturnsFactor: z.number().min(0).max(1).default(0.5).optional(),
    })
    .optional(),
  disambiguation: z
    .object({
      pairwiseAdjustments: z.boolean().default(true),
      confidenceGapThreshold: ThresholdSchema.default(0.1),
      maxAdjustmentsPerCategory: z.number().int().min(1).default(3).optional(),
    })
    .optional(),
  multiLabelSelection: z.object({
    maxLabels: z.number().int().min(1).default(3),
    minSecondaryConfidence: ThresholdSchema.default(0.6),
    allowedCombinations: z
      .array(
        z.object({
          categories: z.array(z.string()),
          maxConfidenceSum: z.number().min(0).default(2.0).optional(),
          notes: z.string().optional(),
        })
      )
      .default([]),
    confidenceGapMinimum: z.number().min(0).default(0.15),
  }),
  aiRouting: z.object({
    highConfidenceThreshold: ThresholdSchema.default(0.8),
    aiRequiredThreshold: ThresholdSchema.default(0.4),
    skipAiConditions: z.array(z.string()).default([]),
    batchSize: z.number().int().min(1).default(10).optional(),
    timeoutMs: z.number().int().min(1000).default(30000).optional(),
  }),
  performance: z
    .object({
      parallelProcessing: z.boolean().default(true),
      maxParallelEmails: z.number().int().min(1).default(10),
      batchSize: z.number().int().min(1).default(50),
      enableCaching: z.boolean().default(true),
      cacheTtlSeconds: z.number().int().min(60).default(3600),
    })
    .optional(),
});

// Confidence thresholds schema
export const ConfidenceThresholdsSchema = z.object({
  highConfidence: ThresholdSchema.default(0.8),
  mediumConfidence: ThresholdSchema.default(0.6),
  lowConfidence: ThresholdSchema.default(0.4),
  aiClassificationRequired: ThresholdSchema.default(0.4),
  manualReviewRequired: ThresholdSchema.default(0.2),
  secondaryLabelMinGap: z.number().min(0).default(0.15),
  tuningParameters: z
    .object({
      confidenceDecayFactor: z.number().min(0).max(1).default(0.95),
      uncertaintyPenalty: z.number().min(0).max(0.5).default(0.1),
    })
    .optional(),
});

// Multi-label policy schema
const MultiLabelPolicySchema = z.object({
  maxTopLevelLabels: z.number().int().min(1).default(3),
  minConfidenceForAdditional: ThresholdSchema.default(0.6),
  allowFinancialActionableCopresence: z.boolean().default(false),
  allowedCombinations: z
    .array(
      z.object({
        categories: z.array(z.string()),
        maxConfidenceSum: z.number().min(0).default(2.0),
        notes: z.string().optional(),
      })
    )
    .default([]),
  exclusions: z
    .array(
      z.object({
        categories: z.array(z.string()),
        reason: z.string(),
      })
    )
    .default([]),
});

// Domain overrides schema
const DomainOverridesSchema = z.record(
  z.string(),
  z.object({
    hardInclude: z.array(DomainSchema).default([]),
    hardExclude: z.array(DomainSchema).default([]),
    strongInclude: z.array(DomainSchema).default([]),
    strongExclude: z.array(DomainSchema).default([]),
    notes: z.string().optional(),
  })
);

// Domain resolution schema
const DomainResolutionSchema = z.object({
  mode: z.enum(['runtimeResolved', 'static', 'hybrid']).default('runtimeResolved'),
  source: z.string().default('config/domain-sources.json'),
  notes: z.string().optional(),
  cacheSettings: z
    .object({
      enableCaching: z.boolean().default(true),
      cacheTtlSeconds: z.number().int().min(60).default(3600),
      maxCacheEntries: z.number().int().min(100).default(10000),
    })
    .optional(),
});

// Attribute system schema
const AttributeSystemSchema = z.object({
  schema: z.record(z.string(), AttributeSchemaDefinition),
  detectors: z.array(AttributeDetectorSchema),
  derived: z.record(z.string(), DerivedAttributeSchema),
  attributeBonusMap: z.record(z.string(), z.record(z.string(), z.number())),
  parallelProcessing: z
    .object({
      enableParallelDetection: z.boolean().default(true),
      maxParallelDetectors: z.number().int().min(1).default(5),
      batchDerivedAttributes: z.boolean().default(true),
    })
    .optional(),
});

// Attribute relevance matrix schema
const AttributeRelevanceMatrixSchema = z
  .object({
    _roles_legend: z
      .object({
        CORE: z.string(),
        PRIMARY_BOOST: z.string(),
        SECONDARY_BOOST: z.string(),
        DISAMBIGUATOR: z.string(),
        FILTER: z.string(),
        STRUCTURAL: z.string(),
        DERIVED_LINK: z.string(),
        NEUTRAL: z.string(),
      })
      .optional(),
  })
  .catchall(
    z.union([
      // Category entry with categoryRoles
      z.object({
        categoryRoles: z.record(z.string(), AttributeRoleSchema).optional(),
        subtypes: z
          .record(
            z.string(),
            z.object({
              roles: z.record(z.string(), AttributeRoleSchema),
            })
          )
          .optional(),
        tuningParameters: z
          .object({
            bonusMultipliers: z.record(z.string(), z.number().min(0).default(1.0)),
            penaltyMultipliers: z.record(z.string(), z.number().min(0).default(1.0)),
            maxInfluence: z.number().min(0).default(0.5),
          })
          .optional(),
      }),
      // Legacy RolesLegend entry (for compatibility)
      z.object({
        CORE: z.string(),
        PRIMARY_BOOST: z.string(),
        SECONDARY_BOOST: z.string(),
        DISAMBIGUATOR: z.string(),
        FILTER: z.string(),
        STRUCTURAL: z.string(),
        DERIVED_LINK: z.string(),
        NEUTRAL: z.string(),
      }),
    ])
  );

// AI prompt system schema
const AIPromptSystemSchema = z.object({
  featureExtraction: z.object({
    systemPrompt: z.array(z.string()),
    userPrompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    maxTokens: z.number().int().min(100).default(1000),
  }),
  finalClassification: z.object({
    systemPrompt: z.array(z.string()),
    userPrompt: z.array(z.string()),
    temperature: z.number().min(0).max(2).default(0.1),
    maxTokens: z.number().int().min(50).default(500),
  }),
  modelSettings: z
    .object({
      modelName: z.string().default('gpt-4'),
      fallbackModel: z.string().default('gpt-3.5-turbo'),
      requestTimeoutMs: z.number().int().min(1000).default(30000),
      retryAttempts: z.number().int().min(0).default(3),
    })
    .optional(),
});

// JSON Schema validation (for feature extraction schema)
const JSONSchemaSchema = z.object({
  type: z.string(),
  properties: z.record(z.string(), z.any()),
  required: z.array(z.string()),
  additionalProperties: z.boolean().default(false),
  $schema: z.string().optional(),
  title: z.string().optional(),
  description: z.string().optional(),
});

// Main processing config schema
const ProcessingConfigSchema = z.object({
  version: z.number().int().min(1),
  taxonomyNotes: z.string(),
  settings: ProcessingSettingsSchema,
  categorySignals: z.record(z.string(), CategorySignalsSchema),
  confidenceThresholds: ConfidenceThresholdsSchema,
  multiLabelPolicy: MultiLabelPolicySchema,
  domainSignalOverrides: DomainOverridesSchema,
  domainSignalResolution: DomainResolutionSchema,
  topLevelCategories: z.record(z.string(), TopLevelCategorySchema),
  attributes: AttributeSystemSchema,
  attributeRelevance: AttributeRelevanceMatrixSchema,
  aiPrompts: AIPromptSystemSchema,
  featureExtractionSchema: JSONSchemaSchema,
});

// Main category configuration schema
export const CategoryConfigurationSchema = z.object({
  version: z.string().regex(/^\d+\.\d+\.\d+$/, 'Must be semantic version format (x.y.z)'),
  lastModified: z.coerce.date(),
  hash: z.string().length(64, 'Must be SHA-256 hash'),

  // Main processing configuration
  processingConfig: ProcessingConfigSchema,

  // Validation metadata
  schemaVersion: z.string().default('1.0.0'),
  validationPassed: z.boolean(),
  validationErrors: z.array(z.string()).default([]),

  // Runtime optimization (these will be populated by the system)
  compiledRules: z
    .array(
      z.object({
        category: z.string(),
        subtype: z.string(),
        tier: z.enum(['high', 'medium', 'low']),
        pattern: z.any(), // RegExp objects can't be validated by Zod
        weight: z.number(),
        parallelSafe: z.boolean().default(true),
      })
    )
    .optional(),

  attributeMatrix: z
    .record(
      z.string(),
      z.record(
        z.string(),
        z.object({
          role: AttributeRoleSchema,
          bonus: z.number(),
          cap: z.number(),
        })
      )
    )
    .optional(),

  // Performance metadata
  performanceMetrics: z
    .object({
      lastValidationTimeMs: z.number().optional(),
      ruleCompilationTimeMs: z.number().optional(),
      matrixComputationTimeMs: z.number().optional(),
      totalCategories: z.number().int().optional(),
      totalRules: z.number().int().optional(),
      parallelCompatibleRules: z.number().int().optional(),
    })
    .optional(),
});

// Type inference
export type CategoryConfiguration = z.infer<typeof CategoryConfigurationSchema>;
export type ProcessingConfig = z.infer<typeof ProcessingConfigSchema>;
export type ProcessingSettings = z.infer<typeof ProcessingSettingsSchema>;
export type CategorySignals = z.infer<typeof CategorySignalsSchema>;
export type ConfidenceThresholds = z.infer<typeof ConfidenceThresholdsSchema>;
export type AttributeRole = z.infer<typeof AttributeRoleSchema>;
export type RulePattern = z.infer<typeof RulePatternSchema>;
export type TopLevelCategory = z.infer<typeof TopLevelCategorySchema>;
export type SubtypeDefinition = z.infer<typeof SubtypeDefinitionSchema>;
export type AttributeSystem = z.infer<typeof AttributeSystemSchema>;
export type AttributeRelevanceMatrix = z.infer<typeof AttributeRelevanceMatrixSchema>;
export type AIPromptSystem = z.infer<typeof AIPromptSystemSchema>;

// Validation helper functions
export const validateCategoryConfiguration = (config: unknown): CategoryConfiguration => {
  return CategoryConfigurationSchema.parse(config);
};

export const validateProcessingConfig = (config: unknown): ProcessingConfig => {
  return ProcessingConfigSchema.parse(config);
};

// Partial validation for specific sections
export const validateCategorySignals = (signals: unknown): CategorySignals => {
  return CategorySignalsSchema.parse(signals);
};

export const validateAttributeSystem = (system: unknown): AttributeSystem => {
  return AttributeSystemSchema.parse(system);
};

export const validateProcessingSettings = (settings: unknown): ProcessingSettings => {
  return ProcessingSettingsSchema.parse(settings);
};

// Schema validation utilities
export const getSchemaVersion = () => '1.0.0';

export const isValidConfig = (config: unknown): boolean => {
  try {
    CategoryConfigurationSchema.parse(config);
    return true;
  } catch {
    return false;
  }
};

export const getValidationErrors = (config: unknown): string[] => {
  try {
    CategoryConfigurationSchema.parse(config);
    return [];
  } catch (error) {
    if (error instanceof z.ZodError) {
      return error.errors.map((err) => `${err.path.join('.')}: ${err.message}`);
    }
    return ['Unknown validation error'];
  }
};

