/**
 * Unit Tests for Rule-Based Scoring Stage
 *
 * Tests the sophisticated lexical pattern matching, bounded aggregation, and scoring logic
 * per SCORING_LOGIC.md "Subtype Scoring Formula" section.
 *
 * Constitutional Compliance:
 * - Law 0: Preserves sophisticated classification engine architecture
 * - Law 1: Comprehensive edge case testing prevents functional harm
 * - Law 2: Tests match implementation requirements exactly
 * - Law 3: Clear, maintainable test structure with explainability validation
 */

import {
  executeRuleScoring,
  RuleScoringStageConfig,
  RuleScoringStageConfigSchema,
} from '../../src/stages/rule-scoring';
import {
  AIPromptSystem,
  AttributeRelevanceMatrix,
  AttributeSystem,
  DomainOverrides,
  DomainResolution,
  EmailMessage,
  JSONSchema,
  MultiLabelPolicy,
  ProcessingConfig,
  ProcessingSettings,
  TopLevelCategory,
} from '../../src/types';
import { createClassificationResult, createClassificationSession } from '../../src/utils/initialization';

// Helper function to set up test session and result
function setupTest() {
  const settings: ProcessingSettings = {
    initialization: {
      applyHardAssertions: true,
      seedCategoryScores: true,
    },
    ruleScoring: {
      useLexicalPatterns: true,
      applySubtypeRules: true,
      boundedAggregation: true,
    },
    attributeProcessing: {
      detectSelfSent: true,
      resolveDomains: true,
      deriveContextFlags: true,
    },
    attributeInfluence: {
      applyBonuses: true,
      applyPenalties: true,
      enforceCaps: true,
    },
    multiLabelSelection: {
      maxLabels: 3,
      minSecondaryConfidence: 0.5,
      allowedCombinations: [],
    },
    aiRouting: {
      highConfidenceThreshold: 0.8,
      aiRequiredThreshold: 0.3,
      skipAiConditions: [],
    },
  };

  const multiLabelPolicy: MultiLabelPolicy = {
    maxTopLevelLabels: 3,
    minConfidenceForAdditional: 0.5,
    allowFinancialActionableCopresence: true,
  };

  const domainOverrides: DomainOverrides = {};

  const domainResolution: DomainResolution = {
    mode: 'runtimeResolved',
    source: 'config/domain-sources.json',
    notes: 'Test config',
  };

  const attributes: AttributeSystem = {
    schema: {},
    detectors: [],
    derived: {},
    attributeBonusMap: {},
  };

  const attributeRelevance: AttributeRelevanceMatrix = {
    RolesLegend: {
      CORE: 'Core attribute',
      PRIMARY_BOOST: 'Primary boost',
      SECONDARY_BOOST: 'Secondary boost',
      DISAMBIGUATOR: 'Disambiguator',
      FILTER: 'Filter',
      STRUCTURAL: 'Structural',
      DERIVED_LINK: 'Derived link',
      NEUTRAL: 'Neutral',
    },
  };

  const aiPrompts: AIPromptSystem = {
    featureExtraction: {
      systemPrompt: ['Extract features'],
      userPrompt: ['Analyze email'],
    },
    finalClassification: {
      systemPrompt: ['Classify email'],
      userPrompt: ['Determine category'],
    },
  };

  const featureExtractionSchema: JSONSchema = {
    type: 'object',
    properties: {},
    required: [],
    additionalProperties: false,
  };

  const processingConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: '',
    settings,
    categorySignals: {},
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.2,
      aiClassificationRequired: 0.3,
      manualReviewRequired: 0.1,
      secondaryLabelMinGap: 0.15,
    },
    multiLabelPolicy: multiLabelPolicy,
    domainSignalOverrides: domainOverrides,
    domainSignalResolution: domainResolution,
    topLevelCategories: {},
    attributes,
    attributeRelevance: attributeRelevance,
    aiPrompts: aiPrompts,
    featureExtractionSchema: featureExtractionSchema,
  };

  const session = createClassificationSession(processingConfig, 'sequential', 1);
  const result = createClassificationResult('test-email-id', session.id, 0);

  // Initialize score breakdown with empty structure
  result.scoreBreakdown.categoryScores = {};

  return { session, result };
}

describe('Rule-Based Scoring Stage', () => {
  let mockEmail: EmailMessage;
  let mockConfig: RuleScoringStageConfig;

  beforeEach(() => {
    // Mock email with rich content for testing various rules
    mockEmail = {
      id: 'test-email-001',
      threadId: 'thread-001',
      gmailLabels: [],
      subject: 'Receipt for your purchase - Order #INV-2024-001',
      from: {
        email: 'receipts@store.com',
        name: 'Store Receipts',
        raw: 'Store Receipts <receipts@store.com>',
      },
      to: [
        {
          email: 'customer@example.com',
          name: 'Customer',
          raw: 'Customer <customer@example.com>',
        },
      ],
      date: new Date('2025-09-28T14:30:00Z'),
      bodyPlain: `Thank you for your purchase!

Order Details:
- Order #: INV-2024-001
- Total: $129.99
- Payment Method: Credit Card ending in 4567
- Date: September 28, 2025

Items:
1. Wireless Headphones - $99.99
2. Shipping - $9.99
3. Tax - $20.01

Your order will be shipped within 2 business days.`,
      bodyHtml: '<h1>Thank you for your purchase!</h1><p>Total: $129.99</p>',
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'Message-ID', value: '<receipt-001@store.com>' },
          { name: 'From', value: 'Store Receipts <receipts@store.com>' },
          { name: 'Subject', value: 'Receipt for your purchase - Order #INV-2024-001' },
        ],
      },
      isProcessed: false,
      processingPriority: 1,
    };

    // Mock configuration with realistic rule patterns
    mockConfig = {
      settings: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Purchase receipts and confirmations',
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['receipt', 'payment confirmation', 'order confirmation'],
                    weight: 12,
                  },
                ],
                mediumConfidence: [
                  {
                    field: 'body',
                    operation: 'containsAny',
                    values: ['total', 'amount', 'charged', 'purchase'],
                    weight: 6,
                  },
                  {
                    field: 'body',
                    operation: 'regexAny',
                    values: ['\\$\\d+\\.\\d{2}', 'USD \\d+'],
                    weight: 8,
                  },
                ],
                lowConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['order', 'item'],
                    weight: 3,
                  },
                ],
              },
            },
            invoice: {
              description: 'Invoices and billing statements',
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['invoice', 'bill', 'statement'],
                    weight: 12,
                  },
                ],
              },
            },
          },
        },
        actionable: {
          description: 'Action-required emails',
          subtypes: {
            explicitAction: {
              description: 'Emails with explicit action requests',
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'startsWith',
                    values: ['TODO:', 'ACTION:', 'TASK:', 'URGENT:'],
                    weight: 15,
                  },
                ],
                mediumConfidence: [
                  {
                    field: 'body',
                    operation: 'containsAny',
                    values: ['please review', 'action required', 'respond by'],
                    weight: 7,
                  },
                ],
              },
            },
          },
        },
      },
      tuningParameters: {
        KHigh: 2,
        KMedium: 2,
        KLow: 2,
        TAIL_DAMPEN: 0.5,
        TAIL_RATIO_CAP: 0.3,
      },
    };
  });

  describe('Configuration Validation', () => {
    it('should validate valid configuration successfully', () => {
      const result = RuleScoringStageConfigSchema.safeParse(mockConfig);
      expect(result.success).toBe(true);
    });

    it('should reject invalid tuning parameters', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {}, // Empty categories
        tuningParameters: {
          ...mockConfig.tuningParameters,
          KHigh: -1, // Invalid - must be >= 0
          KMedium: -0.5, // Invalid - must be >= 0
          KLow: -0.3, // Invalid - must be >= 0
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
      expect(result.error?.issues.length).toBeGreaterThanOrEqual(3); // At least 3 errors (KHigh, KMedium, KLow)
    });

    it('should reject unknown rule operations', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Test',
            subtypes: {
              test: {
                description: 'Test',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'invalidOperation' as string,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
    });
  });

  describe('executeRuleScoring()', () => {
    it('should process emails with rule matches successfully', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring.length).toBeGreaterThan(0);
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBeGreaterThan(0);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
    });

    it('should calculate sophisticated bounded aggregation correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult).toBeDefined();
      expect(financialResult!.subtypeScores.receipt).toBeDefined();

      // Should have multiple rule matches with different weights
      const receiptScore = financialResult!.subtypeScores.receipt;
      expect(receiptScore.ruleMatches.length).toBeGreaterThan(1);
      expect(receiptScore.totalScore).toBeGreaterThan(12); // High confidence + medium matches

      // Verify bounded aggregation breakdown
      expect(receiptScore.aggregationBreakdown).toContain(':');
      expect(financialResult!.scoringRationale[0]).toContain('Rule aggregation:');
    });

    it('should handle emails with no rule matches', () => {
      const emptyEmail: EmailMessage = {
        ...mockEmail,
        subject: 'Random subject with no patterns',
        bodyPlain: 'This is just random content with no matching patterns',
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
