/**
 * Unit Tests for Rule-Based Scoring Stage
 *
 * Tests the sophisticated lexical pattern matching, bounded aggregation, and scoring logic
 * per SCORING_LOGIC.md "Subtype Scoring Formula" section.
 *
 * Constitutional Compliance:
 * - Law 0: Preserves sophisticated classification engine architecture
 * - Law 1: Comprehensive edge case testing prevents functional harm
 * - Law 2: Tests match implementation requirements exactly
 * - Law 3: Clear, maintainable test structure with explainability validation
 */

import {
  executeRuleScoring,
  RuleScoringStageConfig,
  RuleScoringStageConfigSchema,
} from '../../src/stages/rule-scoring';
import {
  AIPromptSystem,
  AttributeRelevanceMatrix,
  AttributeSystem,
  DomainOverrides,
  DomainResolution,
  EmailMessage,
  JSONSchema,
  MultiLabelPolicy,
  ProcessingConfig,
  ProcessingSettings,
  TopLevelCategory,
} from '../../src/types';
import { createClassificationResult, createClassificationSession } from '../../src/utils/initialization';

// Helper function to set up test session and result
function setupTest() {
  const settings: ProcessingSettings = {
    initialization: {
      applyHardAssertions: true,
      seedCategoryScores: true,
    },
    ruleScoring: {
      useLexicalPatterns: true,
      applySubtypeRules: true,
      boundedAggregation: true,
    },
    attributeProcessing: {
      detectSelfSent: true,
      resolveDomains: true,
      deriveContextFlags: true,
    },
    attributeInfluence: {
      applyBonuses: true,
      applyPenalties: true,
      enforceCaps: true,
    },
    multiLabelSelection: {
      maxLabels: 3,
      minSecondaryConfidence: 0.5,
      allowedCombinations: [],
    },
    aiRouting: {
      highConfidenceThreshold: 0.8,
      aiRequiredThreshold: 0.3,
      skipAiConditions: [],
    },
  };

  const multiLabelPolicy: MultiLabelPolicy = {
    maxTopLevelLabels: 3,
    minConfidenceForAdditional: 0.5,
    allowFinancialActionableCopresence: true,
  };

  const domainOverrides: DomainOverrides = {};

  const domainResolution: DomainResolution = {
    mode: 'runtimeResolved',
    source: 'config/domain-sources.json',
    notes: 'Test config',
  };

  const attributes: AttributeSystem = {
    schema: {},
    detectors: [],
    derived: {},
    attributeBonusMap: {},
  };

  const attributeRelevance: AttributeRelevanceMatrix = {
    RolesLegend: {
      CORE: 'Core attribute',
      PRIMARY_BOOST: 'Primary boost',
      SECONDARY_BOOST: 'Secondary boost',
      DISAMBIGUATOR: 'Disambiguator',
      FILTER: 'Filter',
      STRUCTURAL: 'Structural',
      DERIVED_LINK: 'Derived link',
      NEUTRAL: 'Neutral',
    },
  };

  const aiPrompts: AIPromptSystem = {
    featureExtraction: {
      systemPrompt: ['Extract features'],
      userPrompt: ['Analyze email'],
    },
    finalClassification: {
      systemPrompt: ['Classify email'],
      userPrompt: ['Determine category'],
    },
  };

  const featureExtractionSchema: JSONSchema = {
    type: 'object',
    properties: {},
    required: [],
    additionalProperties: false,
  };

  const processingConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: '',
    settings,
    categorySignals: {},
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.2,
      aiClassificationRequired: 0.3,
      manualReviewRequired: 0.1,
      secondaryLabelMinGap: 0.15,
    },
    multiLabelPolicy: multiLabelPolicy,
    domainSignalOverrides: domainOverrides,
    domainSignalResolution: domainResolution,
    topLevelCategories: {},
    attributes,
    attributeRelevance: attributeRelevance,
    aiPrompts: aiPrompts,
    featureExtractionSchema: featureExtractionSchema,
  };

  const session = createClassificationSession(processingConfig, 'sequential', 1);
  const result = createClassificationResult('test-email-id', session.id, 0);

  // Initialize score breakdown with empty structure
  result.scoreBreakdown.categoryScores = {};

  return { session, result };
}

describe('Rule-Based Scoring Stage', () => {
  let mockEmail: EmailMessage;
  let mockConfig: RuleScoringStageConfig;

  beforeEach(() => {
    // Mock email with rich content for testing various rules
    mockEmail = {
      id: 'test-email-001',
      threadId: 'thread-001',
      gmailLabels: [],
      subject: 'Receipt for your purchase - Order #INV-2024-001',
      from: {
        email: 'receipts@store.com',
        name: 'Store Receipts',
        raw: 'Store Receipts <receipts@store.com>',
      },
      to: [
        {
          email: 'customer@example.com',
          name: 'Customer',
          raw: 'Customer <customer@example.com>',
        },
      ],
      date: new Date('2025-09-28T14:30:00Z'),
      bodyPlain: `Thank you for your purchase!

Order Details:
- Order #: INV-2024-001
- Total: $129.99
- Payment Method: Credit Card ending in 4567
- Date: September 28, 2025

Items:
1. Wireless Headphones - $99.99
2. Shipping - $9.99
3. Tax - $20.01

Your order will be shipped within 2 business days.`,
      bodyHtml: '<h1>Thank you for your purchase!</h1><p>Total: $129.99</p>',
      payload: {
        mimeType: 'text/plain',
        headers: [
          { name: 'Message-ID', value: '<receipt-001@store.com>' },
          { name: 'From', value: 'Store Receipts <receipts@store.com>' },
          { name: 'Subject', value: 'Receipt for your purchase - Order #INV-2024-001' },
        ],
      },
      isProcessed: false,
      processingPriority: 1,
    };

    // Mock configuration with realistic rule patterns
    mockConfig = {
      settings: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Purchase receipts and confirmations',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['receipt', 'payment confirmation', 'order confirmation'],
                    weight: 12,
                  },
                ],
                mediumConfidence: [
                  {
                    field: 'body',
                    operation: 'containsAny',
                    values: ['total', 'amount', 'charged', 'purchase'],
                    weight: 6,
                  },
                  {
                    field: 'body',
                    operation: 'regexAny',
                    values: ['\\$\\d+\\.\\d{2}', 'USD \\d+'],
                    weight: 8,
                  },
                ],
                lowConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['order', 'item'],
                    weight: 3,
                  },
                ],
              },
            },
            invoice: {
              description: 'Invoices and billing statements',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'containsAny',
                    values: ['invoice', 'bill', 'statement'],
                    weight: 12,
                  },
                ],
              },
            },
          },
          aiFinalClassification: {
            categoryDescription: 'Financial and monetary communications',
            decisionCriteria: ['Contains financial transactions or account information'],
          },
        },
        actionable: {
          description: 'Action-required emails',
          subtypes: {
            explicitAction: {
              description: 'Emails with explicit action requests',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  {
                    field: 'subject',
                    operation: 'startsWith',
                    values: ['TODO:', 'ACTION:', 'TASK:', 'URGENT:'],
                    weight: 15,
                  },
                ],
                mediumConfidence: [
                  {
                    field: 'body',
                    operation: 'containsAny',
                    values: ['please review', 'action required', 'respond by'],
                    weight: 7,
                  },
                ],
              },
            },
          },
          aiFinalClassification: {
            categoryDescription: 'Emails requiring user action',
            decisionCriteria: ['Contains explicit or implicit action requests'],
          },
        },
      },
      tuningParameters: {
        KHigh: 2,
        KMedium: 2,
        KLow: 2,
        TAIL_DAMPEN: 0.5,
        TAIL_RATIO_CAP: 0.3,
      },
    };
  });

  describe('Configuration Validation', () => {
    it('should validate valid configuration successfully', () => {
      const result = RuleScoringStageConfigSchema.safeParse(mockConfig);
      expect(result.success).toBe(true);
    });

    it('should reject invalid tuning parameters', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {}, // Empty categories
        tuningParameters: {
          ...mockConfig.tuningParameters,
          KHigh: -1, // Invalid - must be >= 0
          KMedium: -0.5, // Invalid - must be >= 0
          KLow: -0.3, // Invalid - must be >= 0
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
      expect(result.error?.issues.length).toBeGreaterThanOrEqual(3); // At least 3 errors (KHigh, KMedium, KLow)
    });

    it('should reject unknown rule operations', () => {
      const invalidConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Test',
            subtypes: {
              test: {
                description: 'Test',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'invalidOperation' as string,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const result = RuleScoringStageConfigSchema.safeParse(invalidConfig);
      expect(result.success).toBe(false);
    });
  });

  describe('executeRuleScoring()', () => {
    it('should process emails with rule matches successfully', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring.length).toBeGreaterThan(0);
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBeGreaterThan(0);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
    });

    it('should calculate sophisticated bounded aggregation correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult).toBeDefined();
      expect(financialResult!.subtypeScores.receipt).toBeDefined();

      // Should have multiple rule matches with different weights
      const receiptScore = financialResult!.subtypeScores.receipt;
      expect(receiptScore.ruleMatches.length).toBeGreaterThan(1);
      expect(receiptScore.totalScore).toBeGreaterThan(12); // High confidence + medium matches

      // Verify bounded aggregation breakdown
      expect(receiptScore.aggregationBreakdown).toContain(':');
      expect(financialResult!.scoringRationale[0]).toContain('Rule aggregation:');
    });

    it('should handle emails with no rule matches', () => {
      const emptyEmail: EmailMessage = {
        ...mockEmail,
        subject: 'Random subject with no patterns',
        bodyPlain: 'This is just random content with no matching patterns',
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(0);
    });

    it("should preserve existing scores when rules don't improve them", () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      // Set high existing score
      result.scoreBreakdown.categoryScores.financial = {
        baseScore: 25.0,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: 25.0,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should use max of existing vs rule score
      expect(result.scoreBreakdown.categoryScores.financial.finalScore).toBeGreaterThanOrEqual(25.0);
    });

    it('should handle disabled rule scoring settings', () => {
      const disabledConfig = {
        ...mockConfig,
        settings: {
          useLexicalPatterns: false,
          applySubtypeRules: false,
          boundedAggregation: true,
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, disabledConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      // Disabled config should not produce rule scoring results
      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(0);
    });

    it('should update context tracking properly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.configurationRefs.ruleScoring).toBe(
        'config.processingConfig.topLevelCategories.*.subtypes.*.ruleBasedClassification'
      );
    });

    it('should handle multiple categories with matches', () => {
      const multiCategoryEmail: EmailMessage = {
        ...mockEmail,
        subject: 'TODO: Review receipt for meeting expenses',
        bodyPlain: 'Please review the total amount charged: $50.00',
      };

      const { session, result } = setupTest();
      result.emailId = multiCategoryEmail.id;
      executeRuleScoring(multiCategoryEmail, session, result, mockConfig);

      expect(
        result.explainabilityTrace.ruleScoring.filter((r) => r.ruleMatches && r.ruleMatches.length > 0).length
      ).toBe(2);
      expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBeGreaterThan(0);
      expect(result.scoreBreakdown.categoryScores.actionable?.finalScore).toBeGreaterThan(0);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const actionableResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'actionable');

      expect(financialResult?.selectedSubtypeId).toBe('receipt');
      expect(actionableResult?.selectedSubtypeId).toBe('explicitAction');
    });
  });

  describe('Rule Evaluation Functions', () => {
    describe('containsAny operation', () => {
      it('should match any value in the list', () => {
        // Test subject content directly via stage execution
        const testEmail = { ...mockEmail, subject: 'Your receipt is ready' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        expect(financialResult?.ruleMatches.some((match) => match.matchedValue === 'receipt')).toBe(true);
      });

      it('should be case insensitive', () => {
        const testEmail = { ...mockEmail, subject: 'RECEIPT for your order' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        expect(financialResult?.ruleMatches.some((match) => match.operation === 'containsAny')).toBe(true);
      });

      it('should not match when no values are found', () => {
        const testEmail = { ...mockEmail, subject: 'Random subject' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        const subjectMatches =
          financialResult?.ruleMatches.filter(
            (match) => match.field === 'subject' && match.operation === 'containsAny'
          ) || [];
        expect(subjectMatches.length).toBe(0);
      });
    });

    describe('startsWith operation', () => {
      it('should match prefixes correctly', () => {
        const testEmail = { ...mockEmail, subject: 'TODO: Review this document' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const actionableResult = result.explainabilityTrace.ruleScoring.find(
          (cat) => cat.categoryCode === 'actionable'
        );
        expect(
          actionableResult?.ruleMatches.some(
            (match) => match.operation === 'startsWith' && match.matchedValue === 'TODO:'
          )
        ).toBe(true);
      });

      it('should be case insensitive for startsWith', () => {
        const testEmail = { ...mockEmail, subject: 'todo: check this' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const actionableResult = result.explainabilityTrace.ruleScoring.find(
          (cat) => cat.categoryCode === 'actionable'
        );
        expect(actionableResult?.ruleMatches.length).toBeGreaterThan(0);
      });
    });

    describe('regexAny operation', () => {
      it('should match regex patterns correctly', () => {
        const testEmail = { ...mockEmail, bodyPlain: 'The total cost is $129.99' };

        const { session, result } = setupTest();
        result.emailId = testEmail.id;
        executeRuleScoring(testEmail, session, result, mockConfig);

        const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
        const regexMatches = financialResult?.ruleMatches.filter((match) => match.operation === 'regexAny') || [];
        expect(regexMatches.length).toBeGreaterThan(0);
        expect(regexMatches[0].matchedValue).toMatch(/\$\d+\.\d{2}/);
      });

      it('should handle invalid regex gracefully', () => {
        const invalidRegexConfig = {
          ...mockConfig,
          topLevelCategories: {
            testCategory: {
              description: 'Test',
              subtypes: {
                testSubtype: {
                  description: 'Test',
                  derived: false,
                  parallelSafe: true,
                  ruleBasedClassification: {
                    mediumConfidence: [
                      {
                        field: 'body' as const,
                        operation: 'regexAny' as const,
                        values: ['[invalid regex pattern'],
                        weight: 5,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Test category',
                decisionCriteria: ['Test criteria'],
              },
            },
          },
        };

        // Spy on console.warn to check error handling
        const consoleSpy = jest.spyOn(console, 'warn').mockImplementation();

        const { session, result } = setupTest();
        result.emailId = mockEmail.id;
        executeRuleScoring(mockEmail, session, result, invalidRegexConfig);

        // console.warn is called with 2 args: (message, error), so check the first arg
        expect(consoleSpy).toHaveBeenCalled();
        const firstCallFirstArg = consoleSpy.mock.calls[0][0];
        expect(firstCallFirstArg).toContain('Invalid regex pattern');
        consoleSpy.mockRestore();
      });
    });

    describe('exists operation', () => {
      it('should match when field has content', () => {
        const existsConfig = {
          ...mockConfig,
          topLevelCategories: {
            testCategory: {
              description: 'Test',
              subtypes: {
                hasSubject: {
                  description: 'Test',
                  derived: false,
                  parallelSafe: true,
                  ruleBasedClassification: {
                    lowConfidence: [
                      {
                        field: 'subject' as const,
                        operation: 'exists' as const,
                        values: [],
                        weight: 2,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Test category',
                decisionCriteria: ['Test criteria'],
              },
            },
          },
        };

        const { session, result } = setupTest();
        result.emailId = mockEmail.id;
        executeRuleScoring(mockEmail, session, result, existsConfig);

        const testResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'testCategory');
        expect(testResult?.ruleMatches.some((match) => match.operation === 'exists')).toBe(true);
      });
    });
  });

  describe('Bounded Aggregation Logic', () => {
    it('should apply KHigh multiplier to sum of ALL high confidence match weights', () => {
      const multiHighConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Test with many high confidence rules',
                ruleBasedClassification: {
                  highConfidence: [
                    { field: 'subject', operation: 'containsAny', values: ['receipt'], weight: 12 },
                    { field: 'subject', operation: 'containsAny', values: ['purchase'], weight: 11 },
                    { field: 'subject', operation: 'containsAny', values: ['order'], weight: 10 },
                    { field: 'body', operation: 'containsAny', values: ['total'], weight: 9 },
                  ],
                },
              },
            },
          },
        },
        tuningParameters: {
          ...mockConfig.tuningParameters,
          KHigh: 1.5, // Multiplier for high confidence tier
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for your purchase order',
        bodyPlain: 'Total amount: $50',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiHighConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      // Per SCORING_LOGIC.md: sum(high_match_weights) * KHigh
      // All 4 rules match: 12 + 11 + 10 + 9 = 42
      // 42 * 1.5 = 63
      const highMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'highConfidence') || [];
      expect(highMatches.length).toBe(4); // All matches included (not topK)

      // Verify score calculation: sum of weights * multiplier
      const highWeightSum = highMatches.reduce((sum, m) => sum + m.weight, 0);
      expect(highWeightSum).toBe(42); // 12 + 11 + 10 + 9
      expect(receiptScore?.totalScore).toBe(63); // 42 * 1.5
    });

    it('should apply multipliers to medium and low confidence tiers', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      const receiptScore = financialResult?.subtypeScores.receipt;

      const mediumMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'mediumConfidence') || [];
      const lowMatches = receiptScore?.ruleMatches.filter((m) => m.tier === 'lowConfidence') || [];

      // Verify tiers are properly categorized
      if (mediumMatches.length > 0) {
        expect(mediumMatches[0].tier).toBe('mediumConfidence');
      }
      if (lowMatches.length > 0) {
        expect(lowMatches[0].tier).toBe('lowConfidence');
      }
    });

    it('should calculate tail support with dampening', () => {
      const multiSubtypeConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              receipt: {
                description: 'Receipt',
                ruleBasedClassification: {
                  highConfidence: [{ field: 'subject', operation: 'containsAny', values: ['receipt'], weight: 15 }],
                },
              },
              invoice: {
                description: 'Invoice',
                ruleBasedClassification: {
                  highConfidence: [{ field: 'subject', operation: 'containsAny', values: ['order'], weight: 12 }],
                },
              },
            },
          },
        },
      };

      const testEmail = {
        ...mockEmail,
        subject: 'Receipt for order confirmation',
      };

      const { session, result } = setupTest();
      result.emailId = testEmail.id;
      executeRuleScoring(testEmail, session, result, multiSubtypeConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.scoringRationale[0]).toContain('primary:');

      // Should have both receipt and invoice subtypes with scores
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('receipt');
      expect(Object.keys(financialResult?.subtypeScores || {})).toContain('invoice');
    });
  });

  describe('Confidence Calculation', () => {
    it('should calculate confidence based on score and match count', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBeGreaterThan(0);
      expect(financialResult?.confidence).toBeLessThanOrEqual(95); // Capped at 95%
    });

    it('should return 0 confidence for zero scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No matching patterns',
        bodyPlain: 'No matching content',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.confidence).toBe(0);
    });
  });

  describe('Subtype Selection', () => {
    it('should select highest scoring subtype', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBe('receipt');
    });

    it('should return null when no subtypes have scores', () => {
      const emptyEmail = {
        ...mockEmail,
        subject: 'No patterns',
        bodyPlain: 'No patterns',
      };

      const { session, result } = setupTest();
      result.emailId = emptyEmail.id;
      executeRuleScoring(emptyEmail, session, result, mockConfig);

      const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');
      expect(financialResult?.selectedSubtypeId).toBeNull();
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing subject and body fields', () => {
      const incompleteEmail: EmailMessage = {
        ...mockEmail,
        subject: '', // Empty subject instead of undefined
        bodyPlain: undefined,
        bodyHtml: undefined,
      };

      const { session, result } = setupTest();
      result.emailId = incompleteEmail.id;
      executeRuleScoring(incompleteEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
    });

    it('should handle empty values arrays in rules', () => {
      const emptyValuesConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              emptyValues: {
                description: 'Test empty values',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject',
                      operation: 'containsAny' as const,
                      values: [],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, emptyValuesConfig);

      // Should handle gracefully without errors
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle subtypes without ruleBasedClassification', () => {
      const noRulesConfig = {
        ...mockConfig,
        topLevelCategories: {
          financial: {
            description: 'Financial communications',
            subtypes: {
              noRules: {
                description: 'Subtype without rules',
                // No ruleBasedClassification
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, noRulesConfig);

      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should handle unknown rule fields gracefully', () => {
      const unknownFieldConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              unknownField: {
                description: 'Test unknown field',
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'unknownField',
                      operation: 'containsAny' as const,
                      values: ['test'],
                      weight: 10,
                    },
                  ],
                },
              },
            },
          },
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, unknownFieldConfig);

      // Should not crash, should handle gracefully
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });

  describe('Performance and Explainability', () => {
    it('should complete processing within reasonable time limits', () => {
      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(1000); // Should complete in under 1 second
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeGreaterThanOrEqual(0);
      expect(result.explainabilityTrace.stageTimings.ruleScoring).toBeLessThan(1000);
    });

    it('should provide complete explainability information', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, mockConfig);

      for (const categoryResult of result.explainabilityTrace.ruleScoring) {
        if (Object.keys(categoryResult.subtypeScores).length > 0) {
          expect(categoryResult.scoringRationale.length).toBeGreaterThan(0);
          expect(categoryResult.ruleMatches).toBeDefined();

          for (const match of categoryResult.ruleMatches) {
            expect(match.field).toBeDefined();
            expect(match.operation).toBeDefined();
            expect(match.tier).toBeDefined();
            expect(match.matchedValue).toBeDefined();
            expect(match.ruleId).toBeDefined();
            expect(match.weight).toBeGreaterThan(0);
          }
        }
      }
    });

    it('should generate consistent results across multiple runs', () => {
      const { session: session1, result: result1 } = setupTest();
      result1.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session1, result1, mockConfig);

      const { session: session2, result: result2 } = setupTest();
      result2.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session2, result2, mockConfig);

      // Compare score breakdowns
      expect(result1.scoreBreakdown.categoryScores).toEqual(result2.scoreBreakdown.categoryScores);
      // Compare explainability traces
      expect(result1.explainabilityTrace.ruleScoring).toEqual(result2.explainabilityTrace.ruleScoring);
    });
  });

  describe('Integration with Classification Pipeline', () => {
    it('should preserve result structure correctly', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      executeRuleScoring(mockEmail, session, result, mockConfig);

      // Should populate result with proper structure
      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });

    it('should work with empty initial category scores', () => {
      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      // Start with empty scores
      result.scoreBreakdown.categoryScores = {};

      executeRuleScoring(mockEmail, session, result, mockConfig);

      expect(result.scoreBreakdown.categoryScores).toBeDefined();
      expect(Object.keys(result.scoreBreakdown.categoryScores).length).toBeGreaterThan(0);
    });

    it('should handle large configuration files efficiently', () => {
      // Create a config with many categories and rules
      const largeConfig = {
        ...mockConfig,
        topLevelCategories: {},
      };

      // Generate 10 categories with 5 subtypes each
      for (let i = 0; i < 10; i++) {
        const categoryName = `category_${i}`;
        (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName] = {
          description: `Category ${i}`,
          subtypes: {},
          aiFinalClassification: {
            categoryDescription: `AI classification for category ${i}`,
            decisionCriteria: [`Criteria for category ${i}`],
          },
        };

        for (let j = 0; j < 5; j++) {
          const subtypeName = `subtype_${i}_${j}`;
          (largeConfig.topLevelCategories as Record<string, TopLevelCategory>)[categoryName].subtypes[subtypeName] = {
            description: `Subtype ${i} ${j}`,
            ruleBasedClassification: {
              highConfidence: [
                {
                  field: 'subject',
                  operation: 'containsAny',
                  values: [`pattern_${i}_${j}`],
                  weight: 10,
                },
              ],
            },
          };
        }
      }

      const startTime = Date.now();

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeRuleScoring(mockEmail, session, result, largeConfig);
      const endTime = Date.now();

      expect(endTime - startTime).toBeLessThan(2000); // Should handle large configs efficiently
      expect(result.explainabilityTrace.ruleScoring).toBeDefined();
    });
  });
});

